package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetNullStringWhenNullStringIsNull() {
        // Create CSVFormat instance with null nullString using reflection since constructor is private
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);
        assertNull(format.getNullString());
    }

    @Test
    void testGetNullStringWhenNullStringIsSet() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        assertEquals("NULL", format.getNullString());
    }

    @Test
    void testGetNullStringWithEmptyString() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("");
        assertEquals("", format.getNullString());
    }
}
